import java.util.*;

public class Solution2 {
public void count(Node root ){
if ( root == null || root.children.isEmpty()){
System.out.println("Number of node in the cluster is : " + 1);
return ;
}

     for(Node n : root.children) {
         n.sendAsynchMessg(root, Type.COUNT_REQUEST.name());
     }
     while (root.children.size() > root.seen.size() ){
         try {
             System.out.println(" waiting  root message received " + root.seen.size());
             Thread.sleep(1000l);
         } catch (InterruptedException e) {
             throw new RuntimeException(e);
         }
     }
     System.out.println("Number of node in the cluster is : " + root.count);
 }


public static void main(String arg []) {
Node root = new Node("1", null);
Node node2 = new Node("2", root);
root.addChild(node2);
Node node3 = new Node("3", root);
root.addChild(node3);
Node node4 = new Node("4", root);
root.addChild(node4);
Node node5 = new Node("5", root);
root.addChild(node5);
Node node6 = new Node("6", root);
root.addChild(node6);

    Node node7 = new Node("7", node2);
    node2.addChild(node7);
    Node node8 = new Node("8", node2);
    node2.addChild(node8);
    Node node9 = new Node("9", node2);
    node2.addChild(node9);

   Node node10 = new Node("10", node3);
   node3.addChild(node10);
   Node node11 = new Node("11", node3);
   node3.addChild(node11);

   Node node12 = new Node("12", node4);
   node4.addChild(node12);

   Node node13 = new Node("13", node5);
   node5.addChild(node13);
   Node node14 = new Node("14", node5);
   node5.addChild(node14);
   Node node15 = new Node("15", node5);
   node5.addChild(node15);
   Node node16 = new Node("16", node5);
   node5.addChild(node16);
   Solution2 solution = new Solution2();
   solution.count(root);


}

static enum Type {
    COUNT_REQUEST,
    COUNT_RESPONSE;
}

static class Node {
    String nodeId;
    List<Node> children ;
    Node parent;
    int count;
    Set<String> seen = new HashSet<>();

    Node(String id, Node parent) {
        this.nodeId = id;
        this.parent = parent;
        children = new ArrayList<>();
        count = 1;
    }

    void addChild(Node id) {
        this.children.add(id);
    }

    public void sendAsynchMessg(Node toNode , String message){

          //Implementation is a simulation for testing. Not required by the problem 
            if ( toNode == null) {
                System.out.println("Done");
                return ;
            }
            toNode.receivedMessage(this , message);   // intended to simulate asyn message reception,
    }

    public void receivedMessage(Node fromNode , String message){

        if ( message.contains(Type.COUNT_RESPONSE.name()) && !seen.contains(fromNode.nodeId)) {
            String [] part = message.split(":");
            if (part.length > 1) {
                 count += Integer.valueOf(part[1]);
            }
            if ( this.seen.size() == children.size() -1 ) {
                 System.out.println("Number of node under  : "  + this.nodeId  + " is " + count);
                 sendAsynchMessg(this.parent, Type.COUNT_RESPONSE.name() +":" + count);
            }

        }else if (message.equals(Type.COUNT_REQUEST.name())){
             if (this.children.isEmpty()){
                 //System.out.println("leaf child sending response") ;
                 sendAsynchMessg(this.parent , Type.COUNT_RESPONSE.name() +":" + 1) ;
             } else {
                for (Node child : children) {
                    sendAsynchMessg(child, Type.COUNT_REQUEST.name());
                }
            }
        }

       seen.add(fromNode.nodeId);  // to avoid duplicate counting
    }

}


}

